WITH "sample" AS (SELECT * FROM "FAKE_PROJECT"."DATASET"."ORDERS" AS t WHERE MOD(ABS(HASH(*)), 10) < 1 LIMIT 100000) SELECT child."CUSTOMER_ID" FROM "sample" AS child LEFT JOIN "FAKE_PROJECT"."DATASET"."CUSTOMERS" AS parent ON child."CUSTOMER_ID" = parent."ID" WHERE child."CUSTOMER_ID" IS NOT NULL AND parent."ID" IS NULL